Here is a clean, fully readable implementation of the physics simulation from scratch. The obfuscated code implements a 2D force-directed graph with nodes, springs, repulsion forces, central gravity, particle emission, and a camera following the nodes. 

I have reverse-engineered the math, renamed all the variables to their logical counterparts, and restructured the control flow to make it clean and maintainable.

```javascript
/**
 * 2D Physics Simulation
 * Reconstructed and cleaned up from the obfuscated source.
 */

// --- Constants & Math Helpers ---
const TWO_PI = 6.283;
const GOLDEN_RATIO = 1.618;
const SIN_45 = 0.707; 
const CENTER_X = 400;
const CENTER_Y = 300;

// --- Simulation Configuration ---
const config = {
    attraction: 4000,          // Repulsive force between nodes (named attraction in obfuscated code but acts as repulsion)
    defaultStiffness: 0.004,   // Default spring coefficient 
    damping: 0.92,             // Velocity retention (friction)
    centralGravity: 0.0003,    // Force pulling nodes to the center point
    maxParticles: 40,          // Maximum number of active particles
    streamDecay: 0.04,         // How fast particles lose their velocity
    cameraEasing: 0.06         // Camera interpolation speed (theta)
};

// --- Entities ---
const nodes = [
    { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const springs = [
    { a: 'hub',   b: 'alpha',   restLength: 160, stiffness: 0.006 },
    { a: 'hub',   b: 'beta',    restLength: 160, stiffness: 0.005 },
    { a: 'hub',   b: 'gamma',   restLength: 170, stiffness: 0.004 },
    { a: 'hub',   b: 'delta',   restLength: 170, stiffness: 0.004 },
    { a: 'hub',   b: 'epsilon', restLength: 180, stiffness: 0.003 },
    { a: 'alpha', b: 'beta',    restLength: 200, stiffness: 0.002 },
    { a: 'gamma', b: 'delta',   restLength: 220, stiffness: 0.002 },
    { a: 'alpha', b: 'epsilon', restLength: 200, stiffness: 0.002 }
];

const particles = [];

// --- Camera System ---
const camera = { x: CENTER_X, y: CENTER_Y, zoom: 1 };
const targetCamera = { x: CENTER_X, y: CENTER_Y, zoom: 1 };

let tickCount = 0;

// --- Helper Functions ---
function getNodeById(id) {
    return nodes.find(node => node.id === id) || null;
}

// --- Core Systems ---

function updatePhysics() {
    // 1. Node Repulsion (N-Body problem approximation)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            const dx = nodes[i].x - nodes[j].x;
            const dy = nodes[i].y - nodes[j].y;
            const distSq = (dx * dx) + (dy * dy);
            const dist = Math.sqrt(distSq) || 1;

            // Inverse-square law for repulsion
            const force = config.attraction / distSq;
            const fx = (dx / dist) * force;
            const fy = (dy / dist) * force;

            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2. Spring Forces (Hooke's Law)
    for (const spring of springs) {
        const nodeA = getNodeById(spring.a);
        const nodeB = getNodeById(spring.b);

        if (!nodeA || !nodeB) continue;

        const dx = nodeB.x - nodeA.x;
        const dy = nodeB.y - nodeA.y;
        const dist = Math.sqrt(dx * dx + dy * dy) || 1;
        const displacement = dist - spring.restLength;

        const force = (spring.stiffness || config.defaultStiffness) * displacement;
        const fx = (dx / dist) * force;
        const fy = (dy / dist) * force;

        nodeA.vx += fx;
        nodeA.vy += fy;
        nodeB.vx -= fx;
        nodeB.vy -= fy;
    }

    // 3. Central Gravity, Damping, and Position Integration
    for (const node of nodes) {
        // Apply weak gravity pulling towards the center
        node.vx += (CENTER_X - node.x) * config.centralGravity;
        node.vy += (CENTER_Y - node.y) * config.centralGravity;

        // Apply damping (friction)
        node.vx *= config.damping;
        node.vy *= config.damping;

        // Apply velocity to position
        node.x += node.vx;
        node.y += node.vy;
    }
}

function spawnParticle() {
    if (particles.length >= config.maxParticles) return;

    // Pick a random node as the origin point
    const sourceNode = nodes[Math.floor(Math.random() * nodes.length)];

    // Calculate random outward velocity
    const angle = Math.random() * TWO_PI;
    const speed = 0.3 + (Math.random() * SIN_45);

    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + (Math.random() * 1200), // Random lifespan between 800 and 2000 ticks
        size: 0.8 + (Math.random() * GOLDEN_RATIO * SIN_45)
    });
}

function updateParticles() {
    // Iterating backwards to safely splice items out of the array
    for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        p.age++;

        // Remove particle if it exceeds its maximum age
        if (p.age > p.maxAge) {
            particles.splice(i, 1);
            continue;
        }

        // Apply velocity decay
        const velocityDecay = 1 - (config.streamDecay * 0.125);
        p.vx *= velocityDecay;
        p.vy *= velocityDecay;

        // Apply velocity to position
        p.x += p.vx;
        p.y += p.vy;
    }
}

function updateCamera() {
    // Smoothly ease the camera towards the target camera properties
    camera.x += (targetCamera.x - camera.x) * config.cameraEasing;
    camera.y += (targetCamera.y - camera.y) * config.cameraEasing;
    camera.zoom += (targetCamera.zoom - camera.zoom) * config.cameraEasing;
}

// --- Main Loop ---

function gameLoop() {
    updatePhysics();
    updateParticles();
    updateCamera();

    // Spawn a particle every 3 ticks
    if (tickCount % 3 === 0) {
        spawnParticle();
    }

    tickCount++;
}

// Run the simulation at roughly 100 frames per second (10ms interval)
setInterval(gameLoop, 10);
